import React from "react";
import {
    Box, Card, CardContent, Button, Alert, Typography, Dialog,
    DialogTitle, DialogContent, DialogContentText, DialogActions,
    TextField, CircularProgress,
} from "@mui/material";
import RestartAltIcon from '@mui/icons-material/RestartAlt';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import { useNavigate } from '@tanstack/react-router';
import { CallStatus } from "@/types/api.types";
import { StatusMessage } from "@/components/StatusMessage";
import { PageContainer } from "@/components/PageContainer";
import { DateTimeReadable } from "@/utils/common";
import { getApiError } from "@/utils/apiError";
import { AuthServices, AuthServicesError } from "@/api";

const RESET_CONFIRM_PHRASE = 'RESET';

/**
 * Reset-authentication screen, ported from SaleOnePos's `SecurityPage` design.
 * Rotates the user's `SecurityKey` (force-logout from all devices) only after
 * an explicit "type RESET to confirm" dialog — guarding against accidental clicks.
 */
export const ResetAuth: React.FC = () => {
    const navigate = useNavigate();

    const [authReset, setAuthReset] = React.useState<CallStatus>(CallStatus.NotStarted);
    const [resetTimestamp, setResetTimestamp] = React.useState<Date | null>(null);
    const [correlationId, setCorrelationId] = React.useState<string | undefined>(undefined);
    const [httpStatus, setHttpStatus] = React.useState<number>(0);

    const [confirmOpen, setConfirmOpen] = React.useState(false);
    const [confirmText, setConfirmText] = React.useState('');

    const resetting = authReset === CallStatus.InProgress;
    const canConfirm = confirmText.trim().toUpperCase() === RESET_CONFIRM_PHRASE && !resetting;

    const closeConfirm = () => {
        if (resetting) return;
        setConfirmOpen(false);
        setConfirmText('');
    };

    const handleResetAuth = () => {
        setAuthReset(CallStatus.InProgress);
        setCorrelationId(undefined);
        setHttpStatus(0);
        AuthServices.ResetMine()
            .then((res: { data?: { status?: number } }) => {
                const status = res?.data?.status ?? 0;
                if (status >= 200 && status < 300) {
                    setAuthReset(CallStatus.Success);
                    setResetTimestamp(new Date());
                    setConfirmOpen(false);
                    setConfirmText('');
                    navigate({ to: '/expired' });
                } else {
                    setAuthReset(CallStatus.Failure);
                    setResetTimestamp(null);
                    setHttpStatus(status);
                }
            })
            .catch((err) => {
                setAuthReset(CallStatus.Failure);
                setResetTimestamp(null);
                const apiErr = getApiError(err);
                setHttpStatus(apiErr.httpStatus);
                setCorrelationId(apiErr.correlationId);
            });
    };

    return (
        <PageContainer
            icon={<RestartAltIcon color="primary" />}
            title="Reset authentication"
            subtitle="Rotate your security key to sign out of every device and invalidate your authenticator setup."
        >
            <Card sx={{ mb: 2 }}>
                <CardContent>
                    <Typography variant="subtitle1" sx={{ mb: 0.5, fontWeight: 600 }}>
                        Reset authentication
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                        Rotates your account's security key. Use this if you suspect your
                        account has been compromised, you've lost your authenticator device, or
                        you want to invalidate old sessions on other browsers.
                    </Typography>

                    <Alert severity="warning" icon={<WarningAmberIcon />} sx={{ mb: 2 }}>
                        <Typography variant="body2" sx={{ mb: 0.5, fontWeight: 600 }}>
                            This action will:
                        </Typography>
                        <Box component="ul" sx={{ pl: 2, m: 0, '& li': { mb: 0.5 } }}>
                            <li><Typography variant="caption">Sign you out of every device immediately.</Typography></li>
                            <li><Typography variant="caption">Invalidate any pending email OTP sent to you.</Typography></li>
                            <li><Typography variant="caption">Replace your authenticator-app QR code — you'll need to scan the new one.</Typography></li>
                        </Box>
                    </Alert>

                    <Button
                        variant="contained"
                        color="error"
                        startIcon={<RestartAltIcon />}
                        onClick={() => setConfirmOpen(true)}
                        disabled={resetting}
                    >
                        Reset my authentication
                    </Button>

                    <StatusMessage
                        currentStatus={authReset}
                        successMessage={resetTimestamp ? `Successfully reset at ${DateTimeReadable(resetTimestamp)}` : 'Successfully reset.'}
                        failureMessage={AuthServicesError.ResetAuthError(httpStatus)}
                        correlationId={correlationId}
                    />
                </CardContent>
            </Card>

            <Dialog open={confirmOpen} onClose={closeConfirm} maxWidth="xs" fullWidth>
                <DialogTitle>Confirm reset</DialogTitle>
                <DialogContent>
                    <DialogContentText sx={{ mb: 2 }}>
                        This will sign you out of every device and rotate your authenticator
                        secret. You will need to log back in with a fresh email OTP and re-scan
                        the new QR code.
                    </DialogContentText>
                    <DialogContentText sx={{ mb: 1 }}>
                        Type <strong>{RESET_CONFIRM_PHRASE}</strong> to confirm:
                    </DialogContentText>
                    <TextField
                        value={confirmText}
                        onChange={(e) => setConfirmText(e.target.value)}
                        placeholder={RESET_CONFIRM_PHRASE}
                        fullWidth
                        autoFocus
                        disabled={resetting}
                        slotProps={{ htmlInput: { 'aria-label': 'Confirmation phrase' } }}
                    />
                </DialogContent>
                <DialogActions>
                    <Button onClick={closeConfirm} disabled={resetting}>Cancel</Button>
                    <Button
                        onClick={handleResetAuth}
                        color="error"
                        variant="contained"
                        disabled={!canConfirm}
                        startIcon={resetting ? <CircularProgress size={16} color="inherit" /> : <RestartAltIcon />}
                    >
                        {resetting ? 'Resetting…' : 'Reset'}
                    </Button>
                </DialogActions>
            </Dialog>
        </PageContainer>
    );
};
